'use strict';

var _index = require('./index');

describe('packets', function () {
  describe('connack', function () {
    describe('encode', function () {
      test('normal', function () {
        expect((0, _index.encode)({
          type: 'connack',
          sessionPresent: false,
          returnCode: 0
        })).toEqual([
        // fixedHeader
        32, // packetType + flags
        2, // remainingLength
        // variableHeader
        0, // connack flags
        0] // return code
        );
      });
    });
    describe('decode', function () {
      test('too short', function () {
        expect((0, _index.decode)(Uint8Array.from([32]))).toBe(null);
        expect((0, _index.decode)(Uint8Array.from([32, 2]))).toBe(null);
        expect((0, _index.decode)(Uint8Array.from([32, 2, 0]))).toBe(null);
      });

      test('normal', function () {
        expect((0, _index.decode)(Uint8Array.from([
        // fixedHeader
        32, // packetType + flags
        2, // remainingLength
        // variableHeader
        0, // connack flags
        0] // return code
        ))).toEqual({
          type: 'connack',
          sessionPresent: false,
          returnCode: 0
        });
      });

      test('sessionPresent', function () {
        expect((0, _index.decode)(Uint8Array.from([
        // fixedHeader
        32, // packetType + flags
        2, // remainingLength
        // variableHeader
        1, // connack flags (sessionPresent)
        0] // return code
        ))).toEqual({
          type: 'connack',
          sessionPresent: true,
          returnCode: 0
        });
      });

      test('returnCode', function () {
        expect((0, _index.decode)(Uint8Array.from([
        // fixedHeader
        32, // packetType + flags
        2, // remainingLength
        // variableHeader
        0, // connack flags
        4] // return code (bad username or password)
        ))).toEqual({
          type: 'connack',
          sessionPresent: false,
          returnCode: 4
        });
      });
    });
  });
});

/* eslint-env jest */